+import { createHash } from "crypto";
+
+export type BillingWebhookEvent = {
+  event_type: string;
+  external_event_id: string;
+  billing_period_id: string;
+  payload: unknown;
+};
+
+export function buildEventFingerprint(event: BillingWebhookEvent): string {
+  const parts = [
+    event.event_type,
+    event.external_event_id,
+    event.billing_period_id,
+  ].join(":");
+  return createHash("sha256").update(parts).digest("hex");
+}
+
+export function buildFingerprintKey(fingerprint: string): string {
+  return `billing:webhook:processed:${fingerprint}`;
+}

