+import { propagation, context, trace, SpanContext } from "@opentelemetry/api";
+import { KafkaMessage } from "kafkajs";
+
+export function extractTraceContext(message: KafkaMessage): ReturnType<typeof context.active> {
+  const carrier: Record<string, string> = {};
+
+  for (const [key, value] of Object.entries(message.headers ?? {})) {
+    if (typeof value === "string") carrier[key] = value;
+    else if (Buffer.isBuffer(value)) carrier[key] = value.toString("utf8");
+  }
+
+  return propagation.extract(context.active(), carrier);
+}
+
+export function withKafkaSpan(
+  ctx: ReturnType<typeof context.active>,
+  spanName: string,
+  attributes: Record<string, string>,
+  fn: () => Promise<void>
+): Promise<void> {
+  const tracer = trace.getTracer("billing-event-pipeline");
+  return context.with(ctx, () => {
+    const span = tracer.startSpan(spanName, { attributes });
+    return context.with(trace.setSpan(context.active(), span), async () => {
+      try {
+        await fn();
+        span.setStatus({ code: 1 });
+      } catch (err) {
+        span.recordException(err as Error);
+        span.setStatus({ code: 2, message: (err as Error).message });
+        throw err;
+      } finally {
+        span.end();
+      }
+    });
+  });
+}

