+import { Pool } from "pg";
+import { Kafka } from "kafkajs";
+import { loadConfig } from "../src/config";
+import { runMigrations } from "../src/db/migrations";
+import { seedBillingEvents } from "./seed/billing-events";
+import { startMockStripe } from "../docker/mock-stripe/server";
+
+async function bootstrap() {
+  console.log("[bootstrap] Loading config...");
+  const config = loadConfig(); // throws on missing/invalid env vars
+
+  const pool = new Pool({ connectionString: config.DATABASE_URL });
+
+  console.log("[bootstrap] Running migrations...");
+  await runMigrations(pool);
+
+  console.log("[bootstrap] Provisioning Kafka topics...");
+  const kafka = new Kafka({ brokers: [config.KAFKA_BROKER] });
+  const admin = kafka.admin();
+  await admin.connect();
+  await admin.createTopics({
+    topics: [
+      { topic: "billing.webhook.events", numPartitions: 6, replicationFactor: 1 },
+      { topic: "billing.invoice.applied", numPartitions: 3, replicationFactor: 1 },
+    ],
+    waitForLeaders: true,
+  });
+  await admin.disconnect();
+
+  console.log("[bootstrap] Seeding billing events...");
+  await seedBillingEvents(pool);
+
+  console.log("[bootstrap] Starting mock Stripe server on :4242...");
+  await startMockStripe({ port: 4242 });
+
+  console.log("[bootstrap] Done. Run `npm run dev` to start the consumer.");
+  await pool.end();
+}
+
+bootstrap().catch((err) => {
+  console.error("[bootstrap] Failed:", err.message);
+  process.exit(1);
+});

