+import express from "express";
+
+export async function startMockStripe({ port }: { port: number }): Promise<void> {
+  const app = express();
+  app.use(express.json());
+
+  const sentEvents: unknown[] = [];
+
+  app.post("/v1/webhooks/send", (req, res) => {
+    const { event_type, external_event_id, billing_period_id, payload } = req.body;
+    if (!event_type || !external_event_id) {
+      return res.status(400).json({ error: "missing required fields" });
+    }
+    sentEvents.push(req.body);
+    res.status(200).json({ received: true, event_type, external_event_id });
+  });
+
+  app.get("/v1/webhooks/sent", (_req, res) => {
+    res.json({ count: sentEvents.length, events: sentEvents });
+  });
+
+  await new Promise<void>((resolve) => app.listen(port, resolve));
+}

