+import { RedisClient } from "../redis/client";
+
+const CURSOR_KEY = "billing:backfill:v2:cursor";
+
+export class BackfillStateStore {
+  constructor(private readonly redis: RedisClient) {}
+
+  async getCursor(): Promise<string | null> {
+    return this.redis.get(CURSOR_KEY);
+  }
+
+  async saveCursor(id: string): Promise<void> {
+    await this.redis.set(CURSOR_KEY, id);
+  }
+
+  async resetCursor(): Promise<void> {
+    await this.redis.del(CURSOR_KEY);
+  }
+}

