+import { Pool } from "pg";
+
+const SAMPLE_SIZE = 1000;
+
+export async function validateV2Parity(pool: Pool): Promise<ValidationResult> {
+  const sample = await pool.query<{ id: string; invoice_id: string; status: string }>(
+    `SELECT id, invoice_id, status FROM billing_events
+     ORDER BY random()
+     LIMIT $1`,
+    [SAMPLE_SIZE]
+  );
+
+  let mismatches = 0;
+  const mismatchDetails: MismatchDetail[] = [];
+
+  for (const v1Row of sample.rows) {
+    const v2Row = await pool.query(
+      `SELECT invoice_id, status, processor_response
+       FROM billing_events_v2
+       WHERE external_event_id = (
+         SELECT external_event_id FROM billing_events WHERE id = $1
+       )`,
+      [v1Row.id]
+    );
+
+    if (v2Row.rowCount === 0) {
+      mismatches++;
+      mismatchDetails.push({ v1Id: v1Row.id, reason: "missing_in_v2" });
+      continue;
+    }
+
+    const v2 = v2Row.rows[0];
+    if (v2.invoice_id !== v1Row.invoice_id || v2.status !== v1Row.status) {
+      mismatches++;
+      mismatchDetails.push({ v1Id: v1Row.id, reason: "field_mismatch", v2 });
+    }
+
+    if (!v2.processor_response) {
+      mismatches++;
+      mismatchDetails.push({ v1Id: v1Row.id, reason: "null_processor_response" });
+    }
+  }
+
+  metrics.gauge("billing.validation.mismatch_count", mismatches);
+
+  return {
+    sampleSize: sample.rowCount,
+    mismatches,
+    mismatchDetails,
+    passedValidation: mismatches === 0,
+  };
+}
